318→    mod proptests {
319→        use super::*;
320→        use proptest::prelude::*;
321→
322→        /// Generate a valid stratum spec string.
323→        fn arb_stratum_spec() -> impl Strategy<Value = String> {
324→            prop_oneof![
325→                // Single positive index
326→                (0..100usize).prop_map(|v| v.to_string()),
327→                // Single negative index
328→                (0..100usize).prop_map(|v| format!("-{v}")),
329→                // Range with both bounds (positive)
330→                (0..50usize, 0..50usize).prop_map(|(a, b)| format!("{a}..{b}")),
331→                // Range with both bounds (negative)
332→                (0..50usize, 0..50usize).prop_map(|(a, b)| format!("-{a}..-{b}")),
333→                // Range with open start
334→                (0..100usize).prop_map(|v| format!("..{v}")),
335→                // Range with open start (negative end)
336→                (0..100usize).prop_map(|v| format!("..-{v}")),
337→                // Range with open end
338→                (0..100usize).prop_map(|v| format!("{v}..")),
339→                // Range with open end (negative start)
340→                (0..100usize).prop_map(|v| format!("-{v}..")),
341→                // Mixed: positive start, negative end
342→                (0..50usize, 0..50usize).prop_map(|(a, b)| format!("{a}..-{b}")),
343→                // Mixed: negative start, positive end
344→                (0..50usize, 0..50usize).prop_map(|(a, b)| format!("-{a}..{b}")),
345→            ]
346→        }
347→
348→        proptest! {
349→            /// Any valid spec string parses successfully.
350→            #[test]
351→            fn valid_specs_always_parse(spec_str in arb_stratum_spec()) {
352→                prop_assert!(parse_stratum_spec(&spec_str).is_ok(),
353→                    "failed to parse valid spec: {}", spec_str);
354→            }
355→
356→            /// Resolved range bounds are always within 0..=max_layer.
357→            #[test]
358→            fn resolved_range_within_bounds(
359→                spec_str in arb_stratum_spec(),
360→                max_layer in 0..50usize,
361→            ) {
362→                let spec = parse_stratum_spec(&spec_str).unwrap();
363→                if let Ok(range) = resolve_range(&spec, max_layer) {
364→                    prop_assert!(*range.start() <= max_layer,
365→                        "start {} > max_layer {}", range.start(), max_layer);
366→                    prop_assert!(*range.end() <= max_layer,
367→                        "end {} > max_layer {}", range.end(), max_layer);
368→                    prop_assert!(range.start() <= range.end(),
369→                        "start {} > end {}", range.start(), range.end());
370→                }
371→            }
372→
373→            /// Negative-zero always resolves to max_layer.
374→            #[test]
375→            fn negative_zero_is_max_layer(max_layer in 0..100usize) {
376→                let spec = parse_stratum_spec("-0").unwrap();
377→                let range = resolve_range(&spec, max_layer).unwrap();
378→                prop_assert_eq!(*range.start(), max_layer);
379→                prop_assert_eq!(*range.end(), max_layer);
380→            }
381→
382→            /// Open-ended ranges span the full extent in their open direction.
383→            #[test]
384→            fn open_start_begins_at_zero(end_val in 0..50usize, max_layer in 0..50usize) {
385→                let spec = parse_stratum_spec(&format!("..{end_val}")).unwrap();
386→                if let Ok(range) = resolve_range(&spec, max_layer) {
387→                    prop_assert_eq!(*range.start(), 0);
388→                }
389→            }
390→
391→            #[test]
392→            fn open_end_reaches_max_layer(start_val in 0..50usize, max_layer in 0..50usize) {
393→                let spec = parse_stratum_spec(&format!("{start_val}..")).unwrap();
394→                if let Ok(range) = resolve_range(&spec, max_layer) {
395→                    prop_assert_eq!(*range.end(), max_layer);
396→                }
397→            }
398→
399→            /// filter_layers returns only indices within the given range.
400→            #[test]
401→            fn filter_layers_indices_in_range(
402→                num_layers in 1..20usize,
403→                range_start in 0..20usize,
404→                range_end in 0..20usize,
405→            ) {
406→                let layers: Vec<Vec<String>> = (0..num_layers)
407→                    .map(|i| vec![format!("fn_{i}")])
408→                    .collect();
409→                let start = range_start.min(range_end);
410→                let end = range_start.max(range_end);
411→                let range = start..=end;
412→                let result = filter_layers(&layers, &range);
413→                for (idx, _) in &result {
414→                    prop_assert!(range.contains(idx),
415→                        "filtered index {} not in range {:?}", idx, range);
416→                    prop_assert!(*idx < num_layers,
417→                        "filtered index {} >= num_layers {}", idx, num_layers);
418→                }
419→                // Count should match the overlap between range and 0..num_layers.
420→                let expected = (start..=end).filter(|i| *i < num_layers).count();
421→                prop_assert_eq!(result.len(), expected);
422→            }
423→
424→            /// Arbitrary strings never cause panics in parse (may return Err).
425→            #[test]
426→            fn arbitrary_input_never_panics(s in ".*") {
427→                let _ = parse_stratum_spec(&s);
428→            }
429→        }
430→    }
431→}
