 237→/// Select a core sample for a specific batch.
 238→///
 239→/// Batch assignment works by stable-hash sorting all functions within each
 240→/// stratum, then assigning batch numbers via round-robin. This produces
 241→/// disjoint, independently representative batches.
 242→///
 243→/// The `total_batches` parameter controls how many batches the population is
 244→/// divided into (derived from the budget: `total / budget`, minimum 2).
 245→pub fn select_batch(
 246→    entries: &[FunctionEntry],
 247→    call_graph: &CallGraph,
 248→    config: &CoreSampleConfig,
 249→    batch_index: usize,
 250→) -> CoreSampleResult {
 251→    if entries.is_empty() {
 252→        return CoreSampleResult {
 253→            selected: HashSet::new(),
 254→            dependency_closure: HashSet::new(),
 255→            strata_summary: Vec::new(),
 256→        };
 257→    }
 258→
 259→    // Compute budget to determine total_batches.
 260→    let total = entries.len();
 261→    let raw_budget = match config.budget {
 262→        SampleBudget::Percentage(pct) => ((pct / 100.0) * total as f64).round() as usize,
 263→        SampleBudget::Absolute(n) => n,
 264→    };
 265→    let budget = raw_budget.min(total).max(1);
 266→    let total_batches = (total / budget).max(2);
 267→
 268→    // Build qualified names.
 269→    let qualified_names: Vec<String> = entries
 270→        .iter()
 271→        .map(|e| FunctionRegistry::qualified_name(&e.file_path, &e.name))
 272→        .collect();
 273→
 274→    // Assign each function a batch via stable-hash round-robin.
 275→    let mut batch_assignments: Vec<(String, usize)> = Vec::with_capacity(entries.len());
 276→    for (i, entry) in entries.iter().enumerate() {
 277→        let qn = &qualified_names[i];
 278→        let file_path = entry.file_path.to_str().unwrap_or("");
 279→        let hash = stable_hash(file_path, &entry.name, config.seed);
 280→        batch_assignments.push((qn.clone(), hash as usize % total_batches));
 281→    }
 282→
 283→    // Select functions assigned to the target batch.
 284→    let selected: HashSet<String> = batch_assignments
 285→        .iter()
 286→        .filter(|(_, batch)| *batch == batch_index % total_batches)
 287→        .map(|(qn, _)| qn.clone())
 288→        .collect();
 289→
 290→    let dependency_closure = compute_dependency_closure(&selected, call_graph);
 291→
 292→    // Build strata summary for the batch (reuse the existing infrastructure).
 293→    let layers = call_graph.topological_layers();
 294→    let mut depth_map: HashMap<&str, usize> = HashMap::new();
 295→    for (layer_idx, layer) in layers.iter().enumerate() {
 296→        for name in layer {
 297→            depth_map.insert(name.as_str(), layer_idx);
 298→        }
 299→    }
 300→
 301→    let mut strata: HashMap<StratumKey, Vec<&str>> = HashMap::new();
 302→    for (i, entry) in entries.iter().enumerate() {
 303→        let qn = qualified_names[i].as_str();
 304→        if !selected.contains(qn) {
 305→            continue;
 306→        }
 307→        let module = module_from_path(&entry.file_path, &config.scan_root);
 308→        let complexity = ComplexityTier::from_branch_count(entry.branch_count);
 309→        let depth = depth_map.get(qn).copied().unwrap_or(0);
 310→        let kind = FunctionKind::classify(entry);
 311→        let key = StratumKey { module, complexity, depth, kind };
 312→        strata.entry(key).or_default().push(qn);
 313→    }
 314→
 315→    let strata_summary = strata
 316→        .iter()
 317→        .map(|(key, members)| StratumInfo {
 318→            label: key.label(),
 319→            total: members.len(),
 320→            sampled: members.len(),
 321→            names: members.iter().map(|n| n.to_string()).collect(),
 322→        })
 323→        .collect();
 324→
 325→    CoreSampleResult {
 326→        selected,
 327→        dependency_closure,
 328→        strata_summary,
 329→    }
 330→}
